def _matches_contract_spec(inputs: dict[str, Any], spec: dict[str, Any]) -> bool:
    return base_f30c._matches_contract_spec(inputs, spec)

def _retained_19b3_label_for_inputs(inputs: dict[str, Any]) -> str | None:
    label = inputs.get('label')
    if label is not None:
        spec = _RESIDUAL_19B3_RETAINED_SPECS.get(str(label))
        if spec is not None and _matches_contract_spec(inputs, spec):
            return str(label)
    for candidate_label, spec in _RESIDUAL_19B3_RETAINED_SPECS.items():
        if _matches_contract_spec(inputs, spec):
            return candidate_label
    return None

def _selected_seed_for_inputs(inputs: dict[str, Any], *, enable_k30: bool=True, enable_rag_k10: bool=True, enable_d64: bool=True, enable_19b3_winners: bool=True) -> tuple[str | None, str | None]:
    if enable_k30 and k30_seed._eligible_k30_q4096(inputs):
        return (SEED_K30_ID, k30_seed.TARGET_SHAPE)
    if enable_rag_k10 and ragk10_direct._eligible_direct_rag_k10(inputs):
        return (SEED_RAG_K10_ID, ragk10_direct.RAG_K10_DIRECT_SHAPE)
    if enable_d64 and d64_seed._eligible_rect_d64(inputs):
        return (SEED_D64_ID, d64_seed.TARGET_SHAPE)
    if enable_19b3_winners:
        label = _retained_19b3_label_for_inputs(inputs)
        if label is not None:
            return (SEED_RESIDUAL_19B3_ID, label)
    return (None, None)

def route_for_contract_inputs(inputs: dict[str, Any], *, force_fallback: bool=False, enable_k30: bool=True, enable_rag_k10: bool=True, enable_d64: bool=True, enable_19b3_winners: bool=False) -> str:
    if not force_fallback:
        selected_seed, _label = _selected_seed_for_inputs(inputs, enable_k30=enable_k30, enable_rag_k10=enable_rag_k10, enable_d64=enable_d64, enable_19b3_winners=enable_19b3_winners)
        if selected_seed == SEED_K30_ID:
            return k30_seed.route_for_contract_inputs(inputs)
        if selected_seed == SEED_RAG_K10_ID:
            return ragk10_direct.route_for_contract_inputs(inputs, enable_residual_19b3=False)
        if selected_seed == SEED_D64_ID:
            return d64_seed.route_for_contract_inputs(inputs)
        if selected_seed == SEED_RESIDUAL_19B3_ID:
            return residual_6998.route_for_contract_inputs(inputs, enable_residual_19b3=True)
    return base_f30c.route_for_contract_inputs(inputs)

def launch_from_contract_inputs(inputs: dict[str, Any], *, force_fallback: bool=False, enable_k30: bool=True, enable_rag_k10: bool=True, enable_d64: bool=True, enable_19b3_winners: bool=False) -> None:
    if not force_fallback:
        selected_seed, _label = _selected_seed_for_inputs(inputs, enable_k30=enable_k30, enable_rag_k10=enable_rag_k10, enable_d64=enable_d64, enable_19b3_winners=enable_19b3_winners)
        if selected_seed == SEED_K30_ID:
            k30_seed.launch_from_contract_inputs(inputs)
            return
        if selected_seed == SEED_RAG_K10_ID:
            ragk10_direct.launch_from_contract_inputs(inputs, enable_residual_19b3=False)
            return
        if selected_seed == SEED_D64_ID:
            d64_seed.launch_from_contract_inputs(inputs)
            return
        if selected_seed == SEED_RESIDUAL_19B3_ID:
            residual_6998.launch_from_contract_inputs(inputs, enable_residual_19b3=True)
            return
    base_f30c.launch_from_contract_inputs(inputs)

